#include <vector>
#include <string>
#include <algorithm>

using namespace std;

long long lcp(const string& s1, const string& s2) {
    int min_len = min(s1.length(), s2.length());
    int i = 0;
    while (i < min_len && s1[i] == s2[i]) {
        i++;
    }
    return i;
}

vector<long long> solve(vector<string> words) {
    int n = words.size();
    vector<long long> answer(n, 0);

    for (int i = 0; i < n; ++i) {
        vector<string> new_words = words;
        new_words.erase(new_words.begin() + i);
        long long max_lcp = 0;
        for (int j = 0; j < new_words.size() - 1; ++j) {
            max_lcp = max(max_lcp, lcp(new_words[j], new_words[j + 1]));
        }
        answer[i] = max_lcp;
    }

    return answer;
}
